patch:
--- a/arithmetic.v
+++ b/arithmetic.v
@@ -8,7 +8,7 @@ module adder_16bit(
   output reg [16:0] sum
 );

-  always @(a or b) begin
+  always @(a or b or carry_in) begin
     sum = a + b + carry_in;
   end

before_code:
module adder_16bit(
  input [15:0] a,
  input [15:0] b,
  input carry_in,
  output reg [16:0] sum
);

  always @(a or b) begin
    sum = a + b + carry_in;
  end

endmodule

after_code:
module adder_16bit(
  input [15:0] a,
  input [15:0] b,
  input carry_in,
  output reg [16:0] sum
);

  always @(a or b or carry_in) begin
    sum = a + b + carry_in;
  end

endmodule
